{%- set cards = doc.get("_bd_cards", []) -%}
{%- set mop_rows = doc.get("_bd_mop_rows", []) -%}
{%- set grand_count = doc.get("_bd_grand_count", 0) -%}
{%- set grand_amount = doc.get("_bd_grand_amount", 0) -%}
{%- set report_date = doc.get("_bd_date", "") -%}
{%- set printed_at = doc.get("_bd_printed_at", "") -%}

<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8"/>
  <title>Daily Billing Summary — {{ report_date }}</title>
  <style>
    *{box-sizing:border-box;margin:0;padding:0}
    body{font-family:'Segoe UI',Roboto,sans-serif;font-size:12px;color:#1f272e;background:#fff;padding:28px 32px}

    /* ── Header ── */
    .pf-header{display:flex;justify-content:space-between;align-items:flex-start;border-bottom:2px solid #2490ef;padding-bottom:12px;margin-bottom:20px}
    .pf-hospital{font-size:18px;font-weight:800;color:#1f272e}
    .pf-sub{font-size:11px;color:#8d99a6;margin-top:3px}
    .pf-meta{text-align:right;font-size:11px;color:#8d99a6;line-height:1.7}
    .pf-meta strong{color:#1f272e;font-size:13px}

    /* ── Section title ── */
    .pf-section{font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.8px;color:#8d99a6;border-left:3px solid #2490ef;padding-left:7px;margin:20px 0 8px}

    /* ── Summary cards row ── */
    .pf-cards{display:flex;gap:8px;flex-wrap:wrap;margin-bottom:6px}
    .pf-card{flex:1;min-width:100px;border:1px solid #d1d8dd;border-radius:6px;padding:10px 12px}
    .pf-card-label{font-size:9px;font-weight:700;text-transform:uppercase;letter-spacing:.4px;color:#8d99a6;margin-bottom:4px}
    .pf-card-count{font-size:20px;font-weight:800;color:#1f272e;line-height:1}
    .pf-card-amount{font-size:11px;font-weight:600;color:#4c5a67;margin-top:2px}
    .pf-card-mop{font-size:9px;color:#8d99a6;margin-top:4px}

    /* ── Detail table ── */
    .pf-table{width:100%;border-collapse:collapse;margin-top:4px}
    .pf-table th{background:#f6f9fc;padding:7px 10px;text-align:left;font-size:10px;font-weight:700;text-transform:uppercase;letter-spacing:.5px;color:#8d99a6;border-bottom:1.5px solid #d1d8dd}
    .pf-table th.r{text-align:right}
    .pf-table th.c{text-align:center}
    .pf-table td{padding:8px 10px;border-bottom:1px solid #ebeef0;color:#1f272e;vertical-align:middle}
    .pf-table td.r{text-align:right;font-weight:600}
    .pf-table td.c{text-align:center;color:#2490ef;font-weight:700}
    .pf-table td.muted{color:#8d99a6}
    .pf-table tr.subtotal td{background:#f0f6ff;font-weight:700;font-size:11px}
    .pf-table tr.grand td{background:#1f272e;color:#fff;font-weight:800;font-size:12px;border:none}

    /* ── MOP breakdown ── */
    .pf-mop-table{width:100%;border-collapse:collapse}
    .pf-mop-table td{padding:6px 10px;border-bottom:1px solid #ebeef0;font-size:12px}
    .pf-mop-table td.r{text-align:right;font-weight:700;color:#2490ef}
    .pf-mop-bar-track{height:5px;background:#e8f3fd;border-radius:99px;overflow:hidden;margin-top:3px}
    .pf-mop-bar-fill{height:5px;background:#2490ef;border-radius:99px}

    /* ── Footer ── */
    .pf-footer{margin-top:28px;border-top:1px solid #d1d8dd;padding-top:10px;display:flex;justify-content:space-between;color:#8d99a6;font-size:10px}

    @media print{
      body{padding:12px 16px}
      .pf-card{page-break-inside:avoid}
    }
  </style>
</head>
<body>

  <!-- ── HEADER ── -->
  <div class="pf-header">
    <div>
      <div class="pf-hospital">🏥 Daily Billing Summary</div>
      <div class="pf-sub">Transaction summary by type &amp; mode of payment</div>
    </div>
    <div class="pf-meta">
      <div><strong>{{ report_date }}</strong></div>
      <div>Printed: {{ printed_at }}</div>
    </div>
  </div>

  <!-- ── TRANSACTION SUMMARY CARDS ── -->
  <div class="pf-section">Transaction Summary</div>
  <div class="pf-cards">
    {%- for card in cards %}
    <div class="pf-card">
      <div class="pf-card-label">{{ card.label }}</div>
      <div class="pf-card-count">{{ card.count }}</div>
      <div class="pf-card-amount">₹ {{ card.amount }}</div>
      {%- if card.mop %}
      <div class="pf-card-mop">{{ card.mop }}</div>
      {%- endif %}
    </div>
    {%- endfor %}
    <!-- Grand Total card -->
    <div class="pf-card" style="border:2px solid #2490ef;background:#f0f7ff;">
      <div class="pf-card-label" style="color:#2490ef">Grand Total</div>
      <div class="pf-card-count">{{ grand_count }}</div>
      <div class="pf-card-amount" style="color:#2490ef;font-size:14px;font-weight:800">₹ {{ grand_amount }}</div>
    </div>
  </div>

  <!-- ── DETAIL TABLE by Type › MOP ── -->
  <div class="pf-section" style="margin-top:24px">Billing Detail — By Department &amp; Mode of Payment</div>
  <table class="pf-table">
    <thead>
      <tr>
        <th>Transaction Type</th>
        <th>Mode of Payment</th>
        <th class="c">Count</th>
        <th class="r">Amount (₹)</th>
      </tr>
    </thead>
    <tbody>
      {%- set ns = namespace(last_type="", type_count=0, type_amount=0) -%}
      {%- for row in mop_rows %}
        {%- if row.type != ns.last_type and ns.last_type != "" %}
          <!-- Subtotal row for previous type -->
          <tr class="subtotal">
            <td colspan="2" style="padding-left:24px">Subtotal — {{ ns.last_type }}</td>
            <td class="c">{{ ns.type_count }}</td>
            <td class="r">₹ {{ ns.type_amount }}</td>
          </tr>
          {%- set ns.type_count = 0 -%}
          {%- set ns.type_amount = "0.00" -%}
        {%- endif %}
        <tr>
          <td>
            {%- if row.type != ns.last_type %}
              <span style="display:inline-block;width:8px;height:8px;border-radius:50%;background:{{ row.dot_color }};margin-right:7px;vertical-align:middle"></span>
              {{ row.type }}
            {%- endif %}
          </td>
          <td class="muted">{{ row.mop }}</td>
          <td class="c">{{ row.count }}</td>
          <td class="r">₹ {{ row.amount }}</td>
        </tr>
        {%- set ns.last_type = row.type -%}
        {%- set ns.type_count = ns.type_count + row.count -%}
      {%- endfor %}
      <!-- Last subtotal -->
      {%- if ns.last_type %}
      <tr class="subtotal">
        <td colspan="2" style="padding-left:24px">Subtotal — {{ ns.last_type }}</td>
        <td class="c">{{ ns.type_count }}</td>
        <td class="r">₹ {{ ns.type_amount }}</td>
      </tr>
      {%- endif %}
      <!-- Grand Total -->
      <tr class="grand">
        <td colspan="2">Grand Total</td>
        <td class="c" style="color:#fff">{{ grand_count }}</td>
        <td class="r" style="color:#fff;font-size:13px">₹ {{ grand_amount }}</td>
      </tr>
    </tbody>
  </table>

