{%- set DEDUCTION_PCT = 12 -%}
{%- set bill_date = frappe.format_date(doc.date_and_time, "dd-MM-yyyy") if doc.date_and_time else "" -%}

{# 1. Load and parse the returned items payload passed from JS #}
{%- set return_items_raw = frappe.form_dict.get('return_items') -%}
{%- if return_items_raw -%}
  {%- set returned_list = frappe.parse_json(return_items_raw) -%}
{%- else -%}
  {# Fallback: if printed outside the return UI, show all items as returned #}
  {%- set returned_list = [] -%}
  {%- for med in doc.medicines or [] -%}
    {%- set _ = returned_list.append({'item_code': med.item_code, 'batch': med.batch, 'qty': med.qty}) -%}
  {%- endfor -%}
{%- endif -%}

{# 2. Match returned list with original medicines to fetch full item details #}
{%- set active_returns = [] -%}
{%- for ret in returned_list -%}
  {%- set found = namespace(item=none) -%}
  {%- for med in doc.medicines or [] -%}
    {%- if med.item_code == ret.item_code and med.batch == ret.batch -%}
      {%- set found.item = med -%}
    {%- endif -%}
  {%- endfor -%}

  {%- if found.item -%}
    {%- set billed_qty = (found.item.qty or 1) | float -%}
    {%- set billed_amt = (found.item.amount or 0) | float -%}
    {%- set ret_qty = (ret.qty or 0) | float -%}
    {%- set row_gross = (billed_amt / billed_qty) * ret_qty -%}
    {%- set row_deduct = row_gross * (DEDUCTION_PCT / 100) -%}
    {%- set row_net = row_gross - row_deduct -%}
    {%- set _ = active_returns.append({
      'hsn': found.item.hsn,
      'item_name': found.item.item_name,
      'batch': found.item.batch,
      'expiry_date': found.item.expiry_date,
      'qty': ret_qty,
      'mrp': found.item.mrp | float,
      'discount_': found.item.discount_ | float,
      'gst_': found.item.gst_ | float,
      'gross': row_gross,
      'deduct': row_deduct,
      'net': row_net
    }) -%}
  {%- endif -%}
{%- endfor -%}

{# 3. Calculate dynamic totals for returning items only #}
{%- set ns = namespace(total_gross=0, total_deduct=0, total_net=0, total_qty=0) -%}
{%- for item in active_returns -%}
  {%- set ns.total_gross = ns.total_gross + item.gross -%}
  {%- set ns.total_deduct = ns.total_deduct + item.deduct -%}
  {%- set ns.total_net = ns.total_net + item.net -%}
  {%- set ns.total_qty = ns.total_qty + item.qty -%}
{%- endfor -%}

