html:
{% set dob = frappe.db.get_value("Patient", doc.patient, "dob") %}
{% set years = 0 %}
{% set months = 0 %}
{% set days = 0 %}
{% if dob %}
    {% set now  = frappe.utils.nowdate() %}
    {% set diff = frappe.utils.date_diff(now, dob) %}
    {% set years = diff//365 %}
    {% set months = (diff - (years * 365))//30 %}
    {% set days = ( (diff - (years * 365)) - (months * 30) ) %}
{% endif %}
{% set age_display = "" %}
{% if years > 0 %}
    {% set age_display = years|str + 'Y' %}
{% else %}
    {% set age_display = months|str + 'M ' + days|str + 'D'  %}
{% endif %}
<div style="font-family: arial, sans-serif;">
    <b><div style="text-align: center; margin-bottom: -2px; font-size:8px;">{{doc.patient_name|upper}}<br>
    {{doc.patient}}, {{age_display}} / {{doc.patient_gender[:1]}}</div>
    <div style="text-align:center;"><img class="barcode" style="width: 350px; height: 50px;" src="data:image/png;base64,{{ generate_barcodes(doc.name) }}"></div>
    <div  style="text-align:center; font-size:8px; margin-top: -8px;">{{doc.name}}</div>
    <div style="text-align: center; font-size:8px;">{{doc.specimen_type|upper}}</div></b>
</div>

{% if doc.lab_items|length <= 10 %}
    <!DOCTYPE html>
    <html lang="en">
    <head>
        <style>
            @page {
                size: A4 portrait;
                margin: 8mm;
            }

            .page-container {
                font-family: Arial, sans-serif;
                width: 100%;
                height: 100%;
                page-break-after: always;
                border: 1px solid #000;
                padding: 1mm;
                overflow: hidden;
                position: relative;
            }

            .invoice-table {
                width: 100%;
                border-collapse: collapse;
                margin: -1px 0 2px 0;
            } 

            .invoice-table td {
                border: 1px solid black;
                padding: 1px;
                margin-top: 0px;
                font-size: 11px; /* Minimum font size */
            }

            .content-wrapper {
                display: flex;
                flex-direction: column;
                height: calc(100% - 25px);
            }

            .order-details {
                width: 100%;
                border-collapse: collapse;
                font-size: 11px; /* Minimum font size */
                flex: 0 0 auto;
                border-bottom: 1px solid black;
            }

            .order-details th, .order-details td {
                padding: 0px; /* Reduce padding to fit more rows */
                font-size: 11px; /* Minimum font size */
                line-height: 0.8; /* Reduce extra spacing */
            }

            .order-details tr.header-row th {
                border: 1px solid black;
                padding: 0px;
                text-align: center;
                font-size: 11px;
            }

            .order-details tr.product-row td {
                border-left: 1px solid black;
                border-right: 1px solid black;
                border-top: none;
                border-bottom: none;
                padding: 0px;
                font-size: 11px;
                line-height: 0.6;
            }

            .order-details tr.total-row th {
                border: 1px solid black;
                padding: 0.5px;
                font-size: 11px;
            }

            .footer-container {
                font-size: 11px;
                margin-top: 2px;
                flex: 0 0 auto;
                width: 100%;
            }

            .footer-container p {
                margin: 0;
                line-height: 1.1;
            }

            .refund-policy {
                margin: 0;
                line-height: 1.2;
            }

            .delivery-contact {
                text-align: center;
                margin-top: 2px;
            }

            .address {
                display: block;
                width: 100%; /* Make sure it takes up the full width of its container */
                word-wrap: break-word; /* Ensures long text wraps */
                word-break: break-word; /* Ensures long words break appropriately */
                overflow: hidden;
                white-space: normal; /* Allow wrapping of text within a block */
            }

            .address span {
                display: inline-block;
                max-width: 100%;
            }


        </style>
    </head>

    <body>
        <div class="page-container">
            <table class="invoice-table">
                <tr>
                    <td style="text-align:right; width: 27.5%;">
                        <img src="/assets/health_sil/images/final_logo_3.png" alt="Clinic Logo" style="object-fit: contain; scale: 1.4">
                    </td>
                    <td style="text-align: center; font-size: 11px; width: 28.5%;">
                        <br>
                        <span style="font-weight: bold;">
                            Kowdiar, Thiruvananthapuram<br>
                            📞 0471-4612849, 2575888<br>
                            E - drrasheeds@gmail.com
                        </span>
                    </td>

                    <td style="text-align:left; font-size: 12px; width: 44%; font-weight: bold;">
                            {% set patient_doc = frappe.get_doc("Patient", doc.patient) %}
                            <span>PID&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;:&nbsp;&nbsp;{{ patient_doc.uid }}</span><br>
                            <span>Name&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;:&nbsp;&nbsp;<span style="font-size:14px;">{{ doc.patient_name }}</span></span><br>
                            <span>Mobile&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;:&nbsp;&nbsp;{{ patient_doc.mobile if patient_doc.mobile else '' }}</span><br>
                            <div class="address">
                                <span>Place&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;:&nbsp;&nbsp;{{ patient_doc.custom_city }}
                                <br>
                            </div>
                            {% set doctor_doc = frappe.get_doc("Healthcare Practitioner", doc.healthcare_practitioner) %}
                            <span>Doctor&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;:&nbsp;&nbsp;<span style="font-size:14px;">{{ doctor_doc.practitioner_name }}</span></span> 
                    </td>
                </tr> 
            </table>

            <div class="content-wrapper">
                <table class="order-details">
                    <tr class="header-row">
                        <th colspan="2" style="width: 60%; font-size: 22px; font-weight: bold; text-align: center;">
                            <br>
                            <span>LAB INVOICE</span>
                        </th>
                        <th colspan="1" style="width: 40%; text-align: start;">
                            <span style="font-weight: bold;">
                                Invoice No: {{ doc.name }}<br><br>
                                Billed by: {{ frappe.session.user }}<br><br>
                                Date: {{ frappe.format_date(doc.date_and_time, "dd-MM-yyyy") }}
                            </span>
                        </th>
                    </tr>

                    <tr class="header-row" style="border-bottom: 1px solid black;">
                        <th style="width: 5%; "><span style="font-weight: bold;">SN</span></th>
                        <th style="width: 55%;"><span style="font-weight: bold;">DESCRIPTION</span></th>
                        <th style="width: 40%;"><span style="font-weight: bold;">AMOUNT</span></th>
                    </tr>

                    {% set max_rows = 10 %}
                    {% set num_items = doc.lab_items|length %}
                    {% for item in doc.lab_items[:max_rows] %}
                    <tr class="product-row">
                        <td style="text-align: center;">{{ loop.index }}</td>
                        <td style="text-align: start;">{{ item.item_name | title }}</td>
                        <td style="text-align: end;">₹ {{ '%.2f'| format(item.amount) }}</td>
                    </tr>
                    {% endfor %}

                    <!-- Fill empty rows if less than 10 items -->
                    {% for i in range(num_items, max_rows) %}
                    <tr class="product-row">
                        <td>&nbsp;</td>
                        <td>&nbsp;</td>
                        <td>&nbsp;</td>
                    </tr>
                    {% endfor %}

                    <!-- Product rows remain same -->

                    <tr class="total-row">
                        <th colspan="2">
                            {% set _words = doc.amount_in_words.replace(" only.", "").replace(" only", "") %}
                            {% set _parts = _words.split(" ", 1) %}
                            <span style="font-weight: bold; font-size: 11px;">{{ _parts[0] }} {{ _parts[1] | capitalize }}</span><br><br>
                            <p style="font-weight: bold; font-size: 12px;"> 
                                TOTAL ITEM : {{ doc.total_items }} &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
                                YOU SAVED RUPEES :₹ {{ "{:,.2f}".format(doc.saved_amount | float) }}
                            </p>
                        </th>
                        <th colspan="1" style="text-align: end;">
                            <span style="font-weight: bold; font-size: 20px;">GRAND TOTAL &nbsp;&nbsp;&nbsp;₹ {{ '%.2f'| format(doc.rounded_total_amount) }}</span>
                        </th>
                    </tr>
                </table>

                <div class="table-border-close"></div>

                <!-- Updated Footer Section -->
                <div class="footer-container" style="display: flex; justify-content: space-between; align-items: flex-start; width: 100%;">
                    <div class="signatory" style="text-align: right; min-width: 200px; font-size: 9px; margin-left: auto;">
                        <br><br><br> <!-- Add space for signature -->
                        <p style="font-weight: bold;">Authorized Signatory</p>
                    </div>
                </div>
            </div>
        </div>
    </body>
    </html>
{% endif%}

